  ('social-worker-moex-00312', 'social-worker', 'social-worker-moex-113-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關社會工作的理論與實務之間的關係，下列敘述何者錯誤？', '["服務對象喜歡社會工作者清楚的告訴他們為什麼要這麼做", "社會服務部門管理強調服務輸送的效率與效益", "社會工作者必須向服務對象與經費提供者負責", "社會工作者不需有太多工作假設，直觀地運用經驗處遇"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "cfb12f7e18eb", "answer_pdf_sha1": "e27a949c51a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
