  ('social-worker-moex-00314', 'social-worker', 'social-worker-moex-113-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '協助服務對象覺知自己的固定行為表現是受到早年生活經驗所影響，以促使其進行適當地修正與 控制，以免妨礙目前的社會生活功能，是屬於心理暨社會學派的那一種會談技巧？', '["人與情境的反映性討論", "型態－動力因素的反映性討論", "人格發展因素的反映性討論", "外在環境的反映性思考"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "cfb12f7e18eb", "answer_pdf_sha1": "e27a949c51a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
